namespace RecipeShare.Models;

public class Category
{
    public string Slug { get; set; } = "";
    public string Name { get; set; } = "";
    public string Icon { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public string Author { get; set; } = "Community";
    public DateTime SubmittedAt { get; set; } = DateTime.UtcNow;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Category> _categories =
    [
        new() { Slug = "breakfast", Name = "Breakfast", Icon = "🥞", Description = "Start your day right with these morning favorites." },
        new() { Slug = "lunch", Name = "Lunch", Icon = "🥗", Description = "Midday meals that keep you fueled." },
        new() { Slug = "dinner", Name = "Dinner", Icon = "🍝", Description = "Hearty dishes for the evening table." },
        new() { Slug = "desserts", Name = "Desserts", Icon = "🍰", Description = "Sweet treats to satisfy your cravings." },
        new() { Slug = "snacks", Name = "Snacks", Icon = "🍿", Description = "Quick bites for any time of day." },
        new() { Slug = "drinks", Name = "Drinks", Icon = "🥤", Description = "Refreshing beverages and cocktails." },
    ];

    private readonly List<Recipe> _recipes;
    private int _nextId;

    // Key: recipeId, Value: list of individual ratings
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Pancakes", CategorySlug = "breakfast", Author = "Chef Amy",
                Ingredients = ["2 cups flour", "2 eggs", "1½ cups milk", "3 tbsp sugar", "1 tsp baking powder", "Pinch of salt", "Butter for the pan"],
                Steps = ["Mix dry ingredients in a bowl.", "Whisk eggs and milk, then combine with dry mix.", "Heat a buttered pan over medium heat.", "Pour ¼ cup batter per pancake.", "Flip when bubbles form; cook until golden."],
            },
            new()
            {
                Id = 2, Title = "Caesar Salad", CategorySlug = "lunch", Author = "Chef Marco",
                Ingredients = ["1 head romaine lettuce", "½ cup croutons", "¼ cup parmesan cheese", "Caesar dressing", "Lemon juice"],
                Steps = ["Wash and chop the lettuce.", "Toss with dressing and lemon juice.", "Top with croutons and parmesan.", "Serve immediately."],
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", CategorySlug = "dinner", Author = "Chef Lucia",
                Ingredients = ["400g spaghetti", "500g ground beef", "1 onion, diced", "2 cloves garlic", "400ml crushed tomatoes", "2 tbsp olive oil", "Salt, pepper, and basil"],
                Steps = ["Cook spaghetti according to package directions.", "Sauté onion and garlic in olive oil.", "Add ground beef and brown thoroughly.", "Stir in crushed tomatoes; season with salt, pepper, basil.", "Simmer 20 minutes; serve over spaghetti."],
            },
            new()
            {
                Id = 4, Title = "Chocolate Lava Cake", CategorySlug = "desserts", Author = "Chef Pierre",
                Ingredients = ["200g dark chocolate", "100g butter", "3 eggs", "100g sugar", "2 tbsp flour"],
                Steps = ["Preheat oven to 220°C (425°F).", "Melt chocolate and butter together.", "Whisk eggs and sugar until fluffy; fold into chocolate.", "Add flour gently.", "Pour into greased ramekins; bake 12 minutes.", "Invert onto plates and serve immediately."],
            },
            new()
            {
                Id = 5, Title = "Guacamole", CategorySlug = "snacks", Author = "Chef Rosa",
                Ingredients = ["3 ripe avocados", "1 lime, juiced", "½ tsp salt", "½ cup diced onion", "1 jalapeño, minced", "2 tbsp cilantro", "1 diced tomato"],
                Steps = ["Mash avocados in a bowl.", "Stir in lime juice and salt.", "Mix in onion, jalapeño, cilantro, and tomato.", "Serve with tortilla chips."],
            },
            new()
            {
                Id = 6, Title = "Mango Smoothie", CategorySlug = "drinks", Author = "Chef Tina",
                Ingredients = ["1 cup frozen mango chunks", "1 banana", "1 cup yogurt", "½ cup orange juice", "1 tbsp honey"],
                Steps = ["Add all ingredients to a blender.", "Blend until smooth.", "Pour into a glass and enjoy."],
            },
        ];
        _nextId = _recipes.Max(r => r.Id) + 1;

        _ratings[1] = [5, 4, 5];
        _ratings[2] = [4, 3];
        _ratings[3] = [5, 5, 4, 5];
        _ratings[4] = [5, 5, 5];
        _ratings[5] = [4, 4, 5];
        _ratings[6] = [3, 4];
    }

    public List<Category> GetCategories() => _categories;

    public Category? GetCategory(string slug) =>
        _categories.FirstOrDefault(c => c.Slug == slug);

    public List<Recipe> GetRecipesByCategory(string categorySlug) =>
        _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetRecipe(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public (double Average, int Count) GetRating(int recipeId)
    {
        if (!_ratings.TryGetValue(recipeId, out var ratings) || ratings.Count == 0)
            return (0, 0);
        return (ratings.Average(), ratings.Count);
    }

    public void AddRating(int recipeId, int stars)
    {
        stars = Math.Clamp(stars, 1, 5);
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];
        _ratings[recipeId].Add(stars);
    }

    public Recipe SubmitRecipe(string title, string categorySlug, List<string> ingredients, List<string> steps, string author)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            CategorySlug = categorySlug,
            Ingredients = ingredients,
            Steps = steps,
            Author = string.IsNullOrWhiteSpace(author) ? "Community" : author,
            SubmittedAt = DateTime.UtcNow,
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

