@page "/category/{Slug}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(category?.Name ?? "Category") — RecipeShare</PageTitle>

<div class="container py-4">
    @if (category is null)
    {
        <div class="alert alert-warning">Category not found.</div>
    }
    else
    {
        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item active">@category.Name</li>
            </ol>
        </nav>

        <h1>@category.Icon @category.Name</h1>
        <p class="lead text-body-secondary">@category.Description</p>

        @if (recipes.Count == 0)
        {
            <p>No recipes in this category yet. <a href="/submit">Be the first to submit one!</a></p>
        }
        else
        {
            <div class="list-group">
                @foreach (var recipe in recipes)
                {
                    var (avg, count) = RecipeService.GetRating(recipe.Id);
                    <a href="/recipe/@recipe.Id" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
                        <div>
                            <h5 class="mb-1">@recipe.Title</h5>
                            <small class="text-body-secondary">by @recipe.Author</small>
                        </div>
                        <span class="badge bg-warning text-dark rounded-pill">
                            @(count > 0 ? $"⭐ {avg:F1} ({count})" : "No ratings")
                        </span>
                    </a>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter] public string Slug { get; set; } = "";

    private RecipeShare.Models.Category? category;
    private List<RecipeShare.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        category = RecipeService.GetCategory(Slug);
        recipes = category is not null ? RecipeService.GetRecipesByCategory(Slug) : [];
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

<div class="container py-4">
    @if (recipe is null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item"><a href="/category/@recipe.CategorySlug">@(category?.Name ?? recipe.CategorySlug)</a></li>
                <li class="breadcrumb-item active">@recipe.Title</li>
            </ol>
        </nav>

        <h1>@recipe.Title</h1>
        <p class="text-body-secondary">Submitted by <strong>@recipe.Author</strong></p>

        <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

        <h3 class="mt-4">🧾 Ingredients</h3>
        <ul class="list-group list-group-flush mb-4">
            @foreach (var item in recipe.Ingredients)
            {
                <li class="list-group-item">@item</li>
            }
        </ul>

        <h3>📋 Steps</h3>
        <ol class="list-group list-group-numbered mb-4">
            @foreach (var step in recipe.Steps)
            {
                <li class="list-group-item">@step</li>
            }
        </ol>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;
    private RecipeShare.Models.Category? category;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipe(Id);
        category = recipe is not null ? RecipeService.GetCategory(recipe.CategorySlug) : null;
    }
}

@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded bg-light">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                title="@star star(s)"
                @onclick="() => Rate(star)">
            @(star <= selectedStar ? "★" : "☆")
        </button>
    }

    @if (average > 0)
    {
        <span class="ms-3 text-body-secondary">
            ⭐ @average.ToString("F1") avg — @count rating(s)
        </span>
    }

    @if (submitted)
    {
        <span class="ms-2 text-success fw-bold">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int selectedStar;
    private double average;
    private int count;
    private bool submitted;

    protected override void OnParametersSet() => LoadRating();

    private void Rate(int stars)
    {
        selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
        LoadRating();
    }

    private void LoadRating()
    {
        (average, count) = RecipeService.GetRating(RecipeId);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Nav

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1>📝 Submit a Recipe</h1>
    <p class="text-body-secondary">Share your favorite recipe with the community.</p>

    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label" for="title">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="category">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.CategorySlug">
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Slug">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
