    }

    @if (submitted)
    {
        <span class="ms-2 text-success fw-bold">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int selectedStar;
    private double average;
    private int count;
    private bool submitted;

    protected override void OnParametersSet() => LoadRating();

    private void Rate(int stars)
    {
        selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
        LoadRating();
    }

    private void LoadRating()
    {
        (average, count) = RecipeService.GetRating(RecipeId);
    }
}

