toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Nav

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1>📝 Submit a Recipe</h1>
    <p class="text-body-secondary">Share your favorite recipe with the community.</p>

    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label" for="title">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="category">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.CategorySlug">
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Slug">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label" for="author">Your Name (optional)</label>
            <InputText id="author" class="form-control" @bind-Value="model.Author" placeholder="Anonymous Chef" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="model.IngredientsText"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.StepsText"
                           placeholder="Preheat oven to 350°F.&#10;Mix all ingredients.&#10;Bake for 30 minutes." />
        </div>

        <button type="submit" class="btn btn-success btn-lg" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>

    @if (submittedRecipe is not null)
    {
        <div class="alert alert-success mt-4">
            <strong>🎉 Recipe submitted!</strong>
            <a href="/recipe/@submittedRecipe.Id">View "@submittedRecipe.Title"</a>
        </div>
    }
</div>

@code {
    private RecipeFormModel model = new();
    private RecipeShare.Models.Recipe? submittedRecipe;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(model.Title) &&
        !string.IsNullOrWhiteSpace(model.CategorySlug) &&
        !string.IsNullOrWhiteSpace(model.IngredientsText) &&
        !string.IsNullOrWhiteSpace(model.StepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var ingredients = model.IngredientsText!
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        var steps = model.StepsText!
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        submittedRecipe = RecipeService.SubmitRecipe(
            model.Title!, model.CategorySlug!, ingredients, steps, model.Author ?? "");

        model = new();
    }

    private class RecipeFormModel
    {
        public string? Title { get; set; }
        public string? CategorySlug { get; set; }
        public string? Author { get; set; }
        public string? IngredientsText { get; set; }
        public string? StepsText { get; set; }
    }
}
